package main

import (
	"errors"
	"fmt"
	"strings"
)

type Book struct {
	Title     string // book title
	Author    string // author name
	ISBN      string // unique id (used as map key in catalog)
	Available bool   // true = on shelf, false = checked out
}

func addBook(catalog map[string]Book, title, author, isbn string, available bool) {
	// catalog[isbn] stores or replaces the Book under that ISBN key
	catalog[isbn] = Book{Title: title, Author: author, ISBN: isbn, Available: available}
}

func searchBooks(catalog map[string]Book, query string) []Book {
	var results []Book
	for _, b := range catalog {
		if strings.Contains(strings.ToLower(b.Title), strings.ToLower(query)) {
			results = append(results, b)
		}
	}
	return results
}

func listBooks(catalog map[string]Book) {
	fmt.Println("| Title                          | Author               | ISBN             | Available |")
	fmt.Println("|--------------------------------|----------------------|-----------------|-----------|")
	for _, b := range catalog {
		fmt.Printf("| %-30s | %-20s | %-15s | %-9t |\n", b.Title, b.Author, b.ISBN, b.Available)
	}
}

func checkout(catalog map[string]Book, isbn string) error {
	book, ok := catalog[isbn]
	if !ok {
		return errors.New("book not found")
	}
	if !book.Available {
		return errors.New("book already checked out")
	}
	book.Available = false
	catalog[isbn] = book
	return nil
}

func returnBook(catalog map[string]Book, isbn string) error {
	book, ok := catalog[isbn]
	if !ok {
		return errors.New("book not found")
	}
	if book.Available {
		return errors.New("book was not checked out")
	}
	book.Available = true
	catalog[isbn] = book
	return nil
}

func stats(catalog map[string]Book) {
	total := len(catalog)
	avail := 0
	for _, b := range catalog {
		if b.Available {
			avail++
		}
	}
	fmt.Printf("Total: %d, Available: %d, Checked out: %d\n", total, avail, total-avail)
}

func loadSampleData() map[string]Book {
	catalog := make(map[string]Book)
	addBook(catalog, "1984", "George Orwell", "978-0451524935", true)
	addBook(catalog, "Dune", "Frank Herbert", "978-0441172719", true)
	addBook(catalog, "Moby Dick", "Herman Melville", "978-0142437247", false)
	addBook(catalog, "The Great Gatsby", "F. Scott Fitzgerald", "978-0743273565", true)
	addBook(catalog, "Brave New World", "Aldous Huxley", "978-0060850524", false)
	return catalog
}

func main() {
	catalog := loadSampleData()
	fmt.Println("=== Welcome to the Library CLI ===")
	fmt.Println("All functions are ready. Now let's build the menu.")

	for {
		fmt.Print("\n1. List books\n2. Search\n3. Checkout\n4. Return\n5. Stats\n0. Exit\nChoose: ")
		var choice int
		fmt.Scanln(&choice)

		switch choice {
		case 1:
			listBooks(catalog)
		case 5:
			stats(catalog)
		case 0:
			fmt.Println("Goodbye!")
			return
		default:
			fmt.Println("Unknown option")
		}
	}
}

